# Functional tests for quality_gate.sh and SKILL.md specification consistency.
# This is a bash test harness because quality_gate.sh is the only executable code.
#
# Usage: bash quality/test_functional.sh
#   Runs all tests and reports PASS/FAIL counts.
#   Exit 0 if all pass, exit 1 if any fail.

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_DIR="$(cd "${SCRIPT_DIR}/.." && pwd)"
GATE="${REPO_DIR}/quality_gate.sh"
PASS=0
FAIL=0
TOTAL=0

pass() { echo "  PASS: $1"; PASS=$((PASS + 1)); TOTAL=$((TOTAL + 1)); }
fail() { echo "  FAIL: $1"; FAIL=$((FAIL + 1)); TOTAL=$((TOTAL + 1)); }

setup_test_dir() {
    local dir
    dir=$(mktemp -d)
    mkdir -p "${dir}/quality"
    echo "$dir"
}

create_minimal_artifacts() {
    local dir="$1"
    local q="${dir}/quality"
    # Create the 6 FAIL-checked artifacts
    echo "# BUGS" > "${q}/BUGS.md"
    echo "# REQUIREMENTS" > "${q}/REQUIREMENTS.md"
    echo "# QUALITY" > "${q}/QUALITY.md"
    echo "# PROGRESS" > "${q}/PROGRESS.md"
    echo "# COVERAGE" > "${q}/COVERAGE_MATRIX.md"
    echo "# COMPLETENESS" > "${q}/COMPLETENESS_REPORT.md"
}

create_full_artifacts() {
    local dir="$1"
    local q="${dir}/quality"
    create_minimal_artifacts "$dir"
    # Create the WARN-checked artifacts
    echo "# CONTRACTS" > "${q}/CONTRACTS.md"
    echo "# RUN_CODE_REVIEW" > "${q}/RUN_CODE_REVIEW.md"
    echo "# RUN_SPEC_AUDIT" > "${q}/RUN_SPEC_AUDIT.md"
    echo "# RUN_INTEGRATION_TESTS" > "${q}/RUN_INTEGRATION_TESTS.md"
    echo "# RUN_TDD_TESTS" > "${q}/RUN_TDD_TESTS.md"
    echo "#!/bin/bash" > "${q}/test_functional.sh"
}

cleanup() {
    [ -n "${1:-}" ] && rm -rf "$1"
}

