# [REQ-001] All Required: Yes artifacts are listed in SKILL.md
test_req001_required_artifacts_listed() {
    local count
    count=$(grep -c "| Yes |" "${REPO_DIR}/SKILL.md" || true)
    if [ "$count" -ge 10 ]; then
        pass "REQ-001: SKILL.md lists ${count} required artifacts (expected >=10)"
    else
