# [REQ-002] quality_gate.sh checks primary artifacts with fail()
test_req002_primary_artifacts_use_fail() {
    # [Req: formal — SKILL.md lines 83-85, quality_gate.sh lines 106-113]
    local all_fail=true
    for artifact in BUGS.md REQUIREMENTS.md QUALITY.md PROGRESS.md COVERAGE_MATRIX.md COMPLETENESS_REPORT.md; do
        if ! grep -A2 "\"${artifact}\"" "${GATE}" 2>/dev/null | grep -q "fail"; then
            # Check via the loop pattern
            if grep -q "for f in.*${artifact}" "${GATE}" 2>/dev/null; then
                local loop_line
                loop_line=$(grep -n "for f in.*${artifact}" "${GATE}" | head -1 | cut -d: -f1)
                if ! sed -n "${loop_line},$((loop_line + 10))p" "${GATE}" | grep -q "fail"; then
                    all_fail=false
                fi
            fi
        fi
    done
    if [ "$all_fail" = true ]; then
        pass "REQ-002: Primary artifacts use fail() in quality_gate.sh"
    else
        fail "REQ-002: Some primary artifacts do not use fail()"
    fi
}
test_req002_primary_artifacts_use_fail

# [REQ-002] KNOWN BUG: Secondary artifacts use warn() instead of fail()
test_req002_secondary_artifacts_severity() {
    # [Req: formal — SKILL.md lines 83-85]
    # This test documents the known inconsistency: these should use fail() per SKILL.md
    # but currently use warn() in quality_gate.sh
    # The gate uses a for-loop at line 117-123 that iterates over these artifacts and uses warn()
    if grep -q "for f in CONTRACTS.md RUN_CODE_REVIEW.md" "${GATE}" 2>/dev/null; then
        # Check if the loop body uses warn
        local loop_start
        loop_start=$(grep -n "for f in CONTRACTS.md" "${GATE}" | head -1 | cut -d: -f1)
        if [ -n "$loop_start" ] && sed -n "${loop_start},$((loop_start + 8))p" "${GATE}" | grep -q "warn"; then
            pass "REQ-002: Confirmed secondary artifacts use warn() in for-loop (known inconsistency with SKILL.md)"
        else
            fail "REQ-002: Secondary artifacts loop found but warn() not detected"
        fi
    else
        fail "REQ-002: Secondary artifacts loop not found in quality_gate.sh"
    fi
}
test_req002_secondary_artifacts_severity

