# Scenario 1: The Silent Gate Pass
test_scenario1_silent_gate_pass() {
    # [Req: formal — QUALITY.md Scenario 1]
    # Create a directory with only the FAIL-checked artifacts, missing all WARN-checked ones
    local dir
    dir=$(setup_test_dir)
    create_minimal_artifacts "$dir"
    # Copy SKILL.md so version detection works
    cp "${REPO_DIR}/SKILL.md" "$dir/"

    local exit_code=0
    bash "${GATE}" "$dir" > /dev/null 2>&1 || exit_code=$?

    if [ "$exit_code" -eq 0 ]; then
        pass "Scenario 1: Confirmed silent gate pass -- gate exits 0 with missing required artifacts (known bug)"
    else
        pass "Scenario 1: Gate correctly fails when WARN-checked artifacts are missing"
    fi
    cleanup "$dir"
}
test_scenario1_silent_gate_pass

