    dir=$(setup_test_dir)
    create_full_artifacts "$dir"
    # Replace test_functional.sh with FunctionalTest.java
    rm "${dir}/quality/test_functional.sh"
    echo "public class FunctionalTest {}" > "${dir}/quality/FunctionalTest.java"
    cp "${REPO_DIR}/SKILL.md" "$dir/"

    local output
    output=$(bash "${GATE}" "$dir" 2>&1 || true)

    if echo "$output" | grep -qi "test_functional.*missing\|WARN.*test_functional"; then
        pass "Scenario 3: Confirmed gate misses FunctionalTest.java (known detection gap)"
    else
        pass "Scenario 3: Gate detects FunctionalTest.java"
    fi
    cleanup "$dir"
}
