# Edge case: json_has_key with key inside string value
test_edge_json_has_key_false_match() {
    # [Req: inferred — quality_gate.sh lines 75-78]
    local tmpfile
    tmpfile=$(mktemp)
    # Create JSON where "verdict" appears only inside a string value, not as a key
    cat > "$tmpfile" << 'JSONEOF'
{
    "id": "BUG-001",
    "description": "The verdict field was missing"
}
JSONEOF
    # json_has_key uses grep for "verdict" -- check if it would match inside the description
    # The word "verdict" appears inside the description value, not as a JSON key
    local match_count
    match_count=$(grep -c '"verdict"' "$tmpfile" 2>/dev/null | tr -d '[:space:]')
    [ -z "$match_count" ] && match_count=0
    if [ "$match_count" -gt 0 ]; then
        pass "Edge: Confirmed json_has_key grep pattern matches 'verdict' inside string values (known limitation)"
    else
        # The test JSON uses the word verdict inside a string value
        # Check if the pattern is present at all
        if grep -q 'verdict' "$tmpfile"; then
            pass "Edge: 'verdict' word present in JSON but not as quoted key (grep would miss it)"
        else
            fail "Edge: Test JSON does not contain the word 'verdict'"
        fi
    fi
    rm -f "$tmpfile"
}
test_edge_json_has_key_false_match

